radix = 255

# Test: simulate both encoder and decoder for a short sequence
# This will help debug the arithmetic coding

class Decoder:
    def __init__(self, data):
        self.data = data
        self.pos = 0
        self.range = 1
        self.fraction = 0
        self.cc = {}

    def get_counts(self, ctx):
        if ctx not in self.cc:
            self.cc[ctx] = [0, 0]
        return self.cc[ctx]

    def gc(self):
        if self.pos >= len(self.data):
            return 0  # would block, but for test we return 0
        b = self.data[self.pos]
        self.pos += 1
        return b

    def get_bit(self, ctx):
        if self.range < radix:
            self.range *= radix
            self.fraction *= radix
            self.fraction += self.gc() - 1
        c = self.get_counts(ctx)
        split = self.range * (c[0] + 1) // (c[0] + c[1] + 2)
        bit = 1 if self.fraction >= split else 0
        if bit:
            self.fraction -= split
            self.range -= split
        else:
            self.range = split
        c[bit] += 1
        return bit

    def get_integer(self, tmp, ctx):
        subtract_it = 1 << tmp
        result_ans = 1
        ctx99 = ctx * 99
        while True:
            tmp += 1
            if self.get_bit(tmp + ctx99):
                break
        tmp -= 1
        for _ in range(tmp):
            result_ans = result_ans * 2 | self.get_bit(ctx99)
        return result_ans - subtract_it

class Encoder:
    def __init__(self):
        self.low = 0
        self.range = 1
        self.out = []
        self.cc = {}

    def get_counts(self, ctx):
        if ctx not in self.cc:
            self.cc[ctx] = [0, 0]
        return self.cc[ctx]

    def emit_byte(self, b):
        self.out.append(b)

    def normalize(self):
        while self.range < radix:
            self.emit_byte(1)  # digit 0
            self.low = self.low * radix + 0
            self.range = self.range * radix

    def encode_bit(self, ctx, bit):
        self.normalize()
        c = self.get_counts(ctx)
        split = self.range * (c[0] + 1) // (c[0] + c[1] + 2)
        if bit:
            self.low += split
            self.range -= split
        else:
            self.range = split
        c[bit] += 1

    def encode_integer(self, tmp_in, ctx, value):
        subtract_it = 1 << tmp_in
        result_ans = value + subtract_it
        actual_tmp = result_ans.bit_length() - 1
        ctx99 = ctx * 99
        for pos in range(tmp_in + 1, actual_tmp + 1):
            self.encode_bit(pos + ctx99, 0)
        self.encode_bit(actual_tmp + 1 + ctx99, 1)
        for i in range(actual_tmp - 1, -1, -1):
            self.encode_bit(ctx99, (result_ans >> i) & 1)

    def finish(self):
        self.normalize()
        # Output the low value as bytes to finalize
        if self.low > 0:
            digits = []
            t = self.low
            while t > 0:
                digits.append(t % radix)
                t //= radix
            for d in reversed(digits):
                self.emit_byte(d + 1)
        self.emit_byte(1)

    def get_output(self):
        return bytes(self.out)

